', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1293', 'auditing-kubernetes-cluster-rbac', 'Auditing Kubernetes Cluster Rbac', '1.0.0', 'security', 'Auditing Kubernetes cluster RBAC configurations to identify overly permissive roles, wildcard permissions, dangerous ClusterRoleBindings, service account abuse, and privilege escalation paths using kubectl, rbac-tool, KubiScan, and Kubeaudit.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1294', 'auditing-terraform-infrastructure-for-security', 'Auditing Terraform Infrastructure For Security', '1.0.0', 'security', 'Auditing Terraform infrastructure-as-code for security misconfigurations using Checkov, tfsec, Terrascan, and OPA/Rego policies to detect overly permissive IAM policies, public resource exposure, missing encryption, and insecure defaults before cloud deployment.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1295', 'automating-ioc-enrichment', 'Automating Ioc Enrichment', '1.0.0', 'security', 'Automates the enrichment of raw indicators of compromise with multi-source threat intelligence context using SOAR platforms, Python pipelines, or TIP playbooks to reduce analyst triage time and standardize enrichment outputs. Use when building automated enrichment workflows integrated with SIEM alerts, email submission pipelines, or bulk IOC processing from threat feeds. Activates for requests involving SOAR enrichment, Cortex XSOAR, Splunk SOAR, TheHive, Python enrichment pipelines, or automate', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1296', 'building-adversary-infrastructure-tracking-system', 'Building Adversary Infrastructure Tracking System', '1.0.0', 'security', 'Build an automated system to track adversary infrastructure using passive DNS, certificate transparency, WHOIS data, and IP enrichment to map and monitor threat actor command-and-control networks.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1297', 'building-attack-pattern-library-from-cti-reports', 'Building Attack Pattern Library From Cti Reports', '1.0.0', 'security', 'Extract and catalog attack patterns from cyber threat intelligence reports into a structured STIX-based library mapped to MITRE ATT&CK for detection engineering and threat-informed defense.', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1298', 'building-automated-malware-submission-pipeline', 'Building Automated Malware Submission Pipeline', '1.0.0', 'security', 'Builds an automated malware submission and analysis pipeline that collects suspicious files from endpoints and email gateways, submits them to sandbox environments and multi-engine scanners, and generates verdicts with IOCs for SIEM integration. Use when SOC teams need to scale malware analysis beyond manual sandbox submissions for high-volume alert triage.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "malware", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1299', 'building-c2-infrastructure-with-sliver-framework', 'Building C2 Infrastructure With Sliver Framework', '1.0.0', 'security', 'Build and configure a resilient command-and-control infrastructure using BishopFox''s Sliver C2 framework with redirectors, HTTPS listeners, and multi-operator support for authorized red team engagements.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1300', 'building-cloud-security-posture-management', 'Building Cloud Security Posture Management', '1.0.0', 'security', 'This skill guides security architects through designing and implementing a cloud security posture management program that continuously monitors infrastructure configurations across AWS, Azure, and GCP. It covers selecting CSPM tooling such as Wiz, Prisma Cloud, or native services, defining policy baselines, automating drift detection, and integrating posture findings into SOC workflows.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1301', 'building-cloud-siem-with-sentinel', 'Building Cloud Siem With Sentinel', '1.0.0', 'security', 'This skill covers deploying Microsoft Sentinel as a cloud-native SIEM and SOAR platform for centralized security operations. It details configuring data connectors for multi-cloud log ingestion, writing KQL detection queries, building automated response playbooks with Logic Apps, and leveraging the Sentinel data lake for petabyte-scale threat hunting across AWS, Azure, and GCP security telemetry.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1302', 'building-detection-rule-with-splunk-spl', 'Building Detection Rule With Splunk Spl', '1.0.0', 'security', 'Build effective detection rules using Splunk Search Processing Language (SPL) correlation searches to identify security threats in SOC environments.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1303', 'building-detection-rules-with-sigma', 'Building Detection Rules With Sigma', '1.0.0', 'security', 'Builds vendor-agnostic detection rules using the Sigma rule format for threat detection across SIEM platforms including Splunk, Elastic, and Microsoft Sentinel. Use when creating portable detection logic from threat intelligence, mapping rules to MITRE ATT&CK techniques, or converting community Sigma rules into platform-specific queries using sigmac or pySigma backends.
', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1304', 'building-devsecops-pipeline-with-gitlab-ci', 'Building Devsecops Pipeline With Gitlab Ci', '1.0.0', 'security', 'Design and implement a comprehensive DevSecOps pipeline in GitLab CI/CD integrating SAST, DAST, container scanning, dependency scanning, and secret detection.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1305', 'building-identity-federation-with-saml-azure-ad', 'Building Identity Federation With Saml Azure Ad', '1.0.0', 'security', 'Establish SAML 2.0 identity federation between on-premises Active Directory and Azure AD (Microsoft Entra ID) for seamless cross-domain authentication and SSO to cloud applications.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1306', 'building-identity-governance-lifecycle-process', 'Building Identity Governance Lifecycle Process', '1.0.0', 'security', 'Builds comprehensive identity governance and lifecycle management processes including joiner-mover-leaver automation, role mining, access request workflows, periodic recertification, and orphaned account remediation using IGA platforms. Activates for requests involving identity lifecycle management, JML processes, role-based access provisioning, or identity governance program design.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1307', 'building-incident-response-dashboard', 'Building Incident Response Dashboard', '1.0.0', 'security', 'Builds real-time incident response dashboards in Splunk, Elastic, or Grafana to provide SOC analysts and leadership with situational awareness during active incidents, tracking affected systems, containment status, IOC spread, and response timeline. Use when IR teams need unified visibility during incident coordination and post-incident reporting.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "forensics", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1308', 'building-incident-response-playbook', 'Building Incident Response Playbook', '1.0.0', 'security', 'Designs and documents structured incident response playbooks that define step-by-step procedures for specific incident types aligned with NIST SP 800-61r3 and SANS PICERL frameworks. Covers playbook structure, decision trees, escalation criteria, RACI matrices, and integration with SOAR platforms. Activates for requests involving IR playbook creation, incident response procedure documentation, response runbook development, or SOAR playbook design.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "forensics", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1309', 'building-incident-timeline-with-timesketch', 'Building Incident Timeline With Timesketch', '1.0.0', 'security', 'Build collaborative forensic incident timelines using Timesketch to ingest, normalize, and analyze multi-source event data for attack chain reconstruction and investigation documentation.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "forensics", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community')
;

