('ACU-SKILL-1310', 'building-ioc-defanging-and-sharing-pipeline', 'Building Ioc Defanging And Sharing Pipeline', '1.0.0', 'security', 'Build an automated pipeline to defang indicators of compromise (URLs, IPs, domains, emails) for safe sharing and distribute them in STIX format through TAXII feeds and threat intelligence platforms.', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1311', 'building-malware-incident-communication-template', 'Building Malware Incident Communication Template', '1.0.0', 'security', 'Build structured communication templates for malware incidents including stakeholder notifications, executive briefings, technical advisories, and regulatory disclosures with severity-based escalation procedures.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "malware", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
