('ACU-SKILL-1313', 'building-phishing-reporting-button-workflow', 'Building Phishing Reporting Button Workflow', '1.0.0', 'security', 'Implement a phishing report button in email clients with automated triage workflow that analyzes user-reported suspicious emails and provides feedback to reporters.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1314', 'building-red-team-c2-infrastructure-with-havoc', 'Building Red Team C2 Infrastructure With Havoc', '1.0.0', 'security', 'Deploy and configure the Havoc C2 framework with teamserver, HTTPS listeners, redirectors, and Demon agents for authorized red team operations.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "red-team", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1315', 'building-role-mining-for-rbac-optimization', 'Building Role Mining For Rbac Optimization', '1.0.0', 'security', 'Apply bottom-up and top-down role mining techniques to discover optimal RBAC roles from existing user-permission assignments, reducing role explosion and enforcing least privilege.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1316', 'building-soc-escalation-matrix', 'Building Soc Escalation Matrix', '1.0.0', 'security', 'Build a structured SOC escalation matrix defining severity tiers, response SLAs, escalation paths, and notification procedures for security incidents.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1317', 'building-soc-metrics-and-kpi-tracking', 'Building Soc Metrics And Kpi Tracking', '1.0.0', 'security', 'Builds SOC performance metrics and KPI tracking dashboards measuring Mean Time to Detect (MTTD), Mean Time to Respond (MTTR), alert quality ratios, analyst productivity, and detection coverage using SIEM data. Use when SOC leadership needs operational visibility, continuous improvement tracking, or executive-level reporting on security operations effectiveness.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1318', 'building-soc-playbook-for-ransomware', 'Building Soc Playbook For Ransomware', '1.0.0', 'security', 'Builds a structured SOC incident response playbook for ransomware attacks covering detection, containment, eradication, and recovery phases with specific SIEM queries, isolation procedures, and decision trees. Use when SOC teams need formalized response procedures for ransomware incidents aligned to NIST SP 800-61 and MITRE ATT&CK ransomware techniques.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "malware", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1319', 'building-threat-actor-profile-from-osint', 'Building Threat Actor Profile From Osint', '1.0.0', 'security', 'Build comprehensive threat actor profiles using open-source intelligence (OSINT) techniques to document adversary motivations, capabilities, infrastructure, and TTPs for proactive defense.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1320', 'building-threat-feed-aggregation-with-misp', 'Building Threat Feed Aggregation With Misp', '1.0.0', 'security', 'Deploy MISP (Malware Information Sharing Platform) to aggregate, correlate, and distribute threat intelligence feeds from multiple sources for centralized IOC management and automated SIEM integration.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "malware", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1321', 'building-threat-hunt-hypothesis-framework', 'Building Threat Hunt Hypothesis Framework', '1.0.0', 'security', 'Build a systematic threat hunt hypothesis framework that transforms threat intelligence, attack patterns, and environmental data into testable hunting hypotheses.', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1322', 'building-threat-intelligence-enrichment-in-splunk', 'Building Threat Intelligence Enrichment In Splunk', '1.0.0', 'security', 'Build automated threat intelligence enrichment pipelines in Splunk Enterprise Security using lookup tables, modular inputs, and the Threat Intelligence Framework.', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1323', 'building-threat-intelligence-feed-integration', 'Building Threat Intelligence Feed Integration', '1.0.0', 'security', 'Builds automated threat intelligence feed integration pipelines connecting STIX/TAXII feeds, open-source threat intel, and commercial TI platforms into SIEM and security tools for real-time IOC matching and alerting. Use when SOC teams need to operationalize threat intelligence by automating feed ingestion, normalization, scoring, and distribution to detection systems.
', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1324', 'building-vulnerability-aging-and-sla-tracking', 'Building Vulnerability Aging And Sla Tracking', '1.0.0', 'security', 'Implement a vulnerability aging dashboard and SLA tracking system to measure remediation performance against severity-based timelines and drive accountability.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "pentesting", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1325', 'building-vulnerability-dashboard-with-defectdojo', 'Building Vulnerability Dashboard With Defectdojo', '1.0.0', 'security', 'Deploy DefectDojo as a centralized vulnerability management dashboard with scanner integrations, deduplication, metrics tracking, and Jira ticketing workflows.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "pentesting", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1326', 'building-vulnerability-exception-tracking-system', 'Building Vulnerability Exception Tracking System', '1.0.0', 'security', 'Build a vulnerability exception and risk acceptance tracking system with approval workflows, compensating controls documentation, and expiration management.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "pentesting", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1327', 'building-vulnerability-scanning-workflow', 'Building Vulnerability Scanning Workflow', '1.0.0', 'security', 'Builds a structured vulnerability scanning workflow using tools like Nessus, Qualys, and OpenVAS to discover, prioritize, and track remediation of security vulnerabilities across infrastructure. Use when SOC teams need to establish recurring vulnerability assessment processes, integrate scan results with SIEM alerting, and build remediation tracking dashboards.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "pentesting", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1328', 'bypassing-authentication-with-forced-browsing', 'Bypassing Authentication With Forced Browsing', '1.0.0', 'security', 'Discovering and accessing unprotected pages, APIs, and administrative interfaces by enumerating URLs and bypassing authentication controls during authorized security assessments.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "red-team", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1329', 'collecting-indicators-of-compromise', 'Collecting Indicators Of Compromise', '1.0.0', 'security', 'Systematically collects, categorizes, and distributes indicators of compromise (IOCs) during and after security incidents to enable detection, blocking, and threat intelligence sharing. Covers network, host, email, and behavioral indicators using STIX/TAXII formats and threat intelligence platforms. Activates for requests involving IOC collection, indicator extraction, threat indicator sharing, compromise indicators, STIX export, or IOC enrichment.
', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1330', 'collecting-open-source-intelligence', 'Collecting Open Source Intelligence', '1.0.0', 'security', 'Collects and synthesizes open-source intelligence (OSINT) about threat actors, malicious infrastructure, and attack campaigns using publicly available data sources, passive reconnaissance tools, and dark web monitoring. Use when investigating external threat actor infrastructure, performing pre-engagement reconnaissance for authorized red team assessments, or enriching CTI reports with publicly available adversary context. Activates for requests involving Maltego, Shodan, OSINT framework, Spider', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1331', 'collecting-volatile-evidence-from-compromised-host', 'Collecting Volatile Evidence From Compromised Host', '1.0.0', 'security', 'Collect volatile forensic evidence from a compromised system following order of volatility, preserving memory, network connections, processes, and system state before they are lost.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "forensics", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
