('ACU-SKILL-1454', 'exploiting-idor-vulnerabilities', 'Exploiting Idor Vulnerabilities', '1.0.0', 'security', 'Identifying and exploiting Insecure Direct Object Reference vulnerabilities to access unauthorized resources by manipulating object identifiers in API requests and URLs.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "pentesting", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
