('ACU-SKILL-1458', 'exploiting-jwt-algorithm-confusion-attack', 'Exploiting Jwt Algorithm Confusion Attack', '1.0.0', 'security', 'Exploits JWT algorithm confusion vulnerabilities where the server''s token verification library accepts the algorithm specified in the JWT header rather than enforcing a fixed algorithm. The tester manipulates the alg header to switch from RS256 to HS256 (using the RSA public key as the HMAC secret), sets alg to none to bypass signature verification, or exploits kid/jku/x5u header injection to supply attacker-controlled keys. Activates for requests involving JWT algorithm confusion, alg none att', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "red-team", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1459', 'exploiting-kerberoasting-with-impacket', 'Exploiting Kerberoasting With Impacket', '1.0.0', 'security', 'Perform Kerberoasting attacks using Impacket''s GetUserSPNs to extract and crack Kerberos TGS tickets for Active Directory service accounts.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "pentesting", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
