('ACU-SKILL-1484', 'hunting-advanced-persistent-threats', 'Hunting Advanced Persistent Threats', '1.0.0', 'security', 'Proactively hunts for Advanced Persistent Threat (APT) activity within enterprise environments using hypothesis-driven searches across endpoint telemetry, network logs, and memory artifacts. Use when conducting scheduled threat hunting cycles, investigating anomalous behavior flagged by UEBA, or validating that known APT TTPs are not present in the environment. Activates for requests involving MITRE ATT&CK, Velociraptor, osquery, Zeek, or threat hunting playbooks.
', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1485', 'hunting-for-beaconing-with-frequency-analysis', 'Hunting For Beaconing With Frequency Analysis', '1.0.0', 'security', 'Identify command-and-control beaconing patterns in network traffic by applying statistical frequency analysis, jitter calculation, and coefficient of variation scoring to detect periodic callbacks from compromised endpoints.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1486', 'hunting-for-command-and-control-beaconing', 'Hunting For Command And Control Beaconing', '1.0.0', 'security', 'Detect C2 beaconing patterns in network traffic using frequency analysis, jitter detection, and domain reputation to identify compromised endpoints communicating with adversary infrastructure.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
