('ACU-SKILL-1490', 'hunting-for-living-off-the-land-binaries', 'Hunting For Living Off The Land Binaries', '1.0.0', 'security', 'Proactively hunt for adversary abuse of legitimate system binaries (LOLBins) to execute malicious payloads while evading detection.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
