('ACU-SKILL-1600', 'implementing-soar-playbook-with-palo-alto-xsoar', 'Implementing Soar Playbook With Palo Alto Xsoar', '1.0.0', 'security', 'Implement automated incident response playbooks in Cortex XSOAR to orchestrate security workflows across SOC tools and reduce manual response time.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1601', 'implementing-supply-chain-security-with-in-toto', 'Implementing Supply Chain Security With In Toto', '1.0.0', 'security', 'Implement software supply chain integrity verification for container builds using the in-toto framework to create cryptographically signed attestations across CI/CD pipeline steps.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1602', 'implementing-taxii-server-with-opentaxii', 'Implementing Taxii Server With Opentaxii', '1.0.0', 'security', 'Deploy and configure an OpenTAXII server to share and consume STIX-formatted cyber threat intelligence using the TAXII 2.1 protocol for automated indicator exchange between organizations.', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1603', 'implementing-threat-intelligence-lifecycle-management', 'Implementing Threat Intelligence Lifecycle Management', '1.0.0', 'security', 'Implement a structured threat intelligence lifecycle encompassing planning, collection, processing, analysis, dissemination, and feedback stages to produce actionable intelligence for organizational decision-making.', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1604', 'implementing-threat-modeling-with-mitre-attack', 'Implementing Threat Modeling With Mitre Attack', '1.0.0', 'security', 'Implements threat modeling using the MITRE ATT&CK framework to map adversary TTPs against organizational assets, assess detection coverage gaps, and prioritize defensive investments. Use when SOC teams need to align detection engineering with threat landscape, conduct threat assessments for new environments, or justify security tool procurement.
', '{"thread": "T06 \u2014 EDNA", "thread_code": "T06", "category": "threat-intelligence", "shard_affinity": "Edna-SIGINT", "layer_access": ["L7", "L8", "L9"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'restricted', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1605', 'implementing-ticketing-system-for-incidents', 'Implementing Ticketing System For Incidents', '1.0.0', 'security', 'Implements an integrated incident ticketing system connecting SIEM alerts to ServiceNow, Jira, or TheHive for structured incident tracking, SLA management, escalation workflows, and compliance documentation. Use when SOC teams need formalized incident lifecycle management with automated ticket creation, assignment routing, and resolution tracking.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1606', 'implementing-usb-device-control-policy', 'Implementing Usb Device Control Policy', '1.0.0', 'security', 'Implements USB device control policies to restrict unauthorized removable media access on endpoints, preventing data exfiltration and malware introduction via USB devices. Use when deploying device control via Group Policy, Intune, or EDR platforms to enforce USB restrictions. Activates for requests involving USB control, removable media policy, device control, or data loss prevention via USB.
', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "malware", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1607', 'implementing-velociraptor-for-ir-collection', 'Implementing Velociraptor For Ir Collection', '1.0.0', 'security', 'Deploy and configure Velociraptor for scalable endpoint forensic artifact collection during incident response using VQL queries, hunts, and pre-built artifact packs across Windows, Linux, and macOS environments.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "forensics", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1608', 'implementing-vulnerability-sla-breach-alerting', 'Implementing Vulnerability Sla Breach Alerting', '1.0.0', 'security', 'Build automated alerting for vulnerability remediation SLA breaches with severity-based timelines, escalation workflows, and compliance reporting dashboards.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "pentesting", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
('ACU-SKILL-1609', 'implementing-zero-knowledge-proof-for-authentication', 'Implementing Zero Knowledge Proof For Authentication', '1.0.0', 'security', 'Zero-Knowledge Proofs (ZKPs) allow a prover to demonstrate knowledge of a secret (such as a password or private key) without revealing the secret itself. This skill implements the Schnorr identificati', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community')
