('ACU-SKILL-1811', 'triaging-security-incident-with-ir-playbook', 'Triaging Security Incident With Ir Playbook', '1.0.0', 'security', 'Classify and prioritize security incidents using structured IR playbooks to determine severity, assign response teams, and initiate appropriate response procedures.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "mukul975/Anthropic-Cybersecurity-Skills"}', 'sovereign', 10.0, 'draft', 'cybersecurity-community'),
