('ACU-SKILL-1816', 'copilot-ai-prompt-engineering-safety-review', 'Ai Prompt Engineering Safety Review', '1.0.0', 'security', 'Comprehensive AI prompt engineering safety review and improvement prompt. Analyzes prompts for safety, bias, security vulnerabilities, and effectiveness while providing detailed improvement recommendations with extensive frameworks, testing methodologies, and educational content.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "github/awesome-copilot"}', 'sovereign', 10.0, 'draft', 'GitHub Copilot Community'),
