('ACU-SKILL-1820', 'copilot-architecture-blueprint-generator', 'Architecture Blueprint Generator', '1.0.0', 'cognitive', 'Comprehensive project architecture blueprint generator that analyzes codebases to create detailed architectural documentation. Automatically detects technology stacks and architectural patterns, generates visual diagrams, documents implementation patterns, and provides extensible blueprints for maintaining architectural consistency and guiding new development.', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-1821', 'copilot-aspire', 'Aspire', '1.0.0', 'infrastructure', 'Aspire skill covering the Aspire CLI, AppHost orchestration, service discovery, integrations, MCP server, VS Code extension, Dev Containers, GitHub Codespaces, templates, dashboard, and deployment. Use when the user asks to create, run, debug, configure, deploy, or troubleshoot an Aspire distributed application.', '{"thread": "T01 \u2014 COSM", "thread_code": "T01", "category": "mcp", "shard_affinity": "ADOCP", "layer_access": ["L5", "L6"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-1822', 'copilot-aspnet-minimal-api-openapi', 'Aspnet Minimal Api Openapi', '1.0.0', 'infrastructure', 'Create ASP.NET Minimal API endpoints with proper OpenAPI documentation', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-azure", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "github/awesome-copilot"}', 'restricted', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-1823', 'copilot-az-cost-optimize', 'Az Cost Optimize', '1.0.0', 'infrastructure', 'Analyze Azure resources used in the app (IaC files and/or resources in a target rg) and optimize costs - creating GitHub issues for identified optimizations.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-azure", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "github/awesome-copilot"}', 'restricted', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-1824', 'copilot-azure-deployment-preflight', 'Azure Deployment Preflight', '1.0.0', 'infrastructure', 'Performs comprehensive preflight validation of Bicep deployments to Azure, including template syntax validation, what-if analysis, and permission checks. Use this skill before any deployment to Azure to preview changes, identify potential issues, and ensure the deployment will succeed. Activate when users mention deploying to Azure, validating Bicep files, checking deployment permissions, previewing infrastructure changes, running what-if, or preparing for azd provision.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-azure", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "github/awesome-copilot"}', 'restricted', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-1825', 'copilot-azure-devops-cli', 'Azure Devops Cli', '1.0.0', 'infrastructure', 'Manage Azure DevOps resources via CLI including projects, repos, pipelines, builds, pull requests, work items, artifacts, and service endpoints. Use when working with Azure DevOps, az commands, devops automation, CI/CD, or when user mentions Azure DevOps CLI.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-azure", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "github/awesome-copilot"}', 'restricted', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-1826', 'copilot-azure-pricing', 'Azure Pricing', '1.0.0', 'infrastructure', 'Fetches real-time Azure retail pricing using the Azure Retail Prices API (prices.azure.com) and estimates Copilot Studio agent credit consumption. Use when the user asks about the cost of any Azure service, wants to compare SKU prices, needs pricing data for a cost estimate, mentions Azure pricing, Azure costs, Azure billing, or asks about Copilot Studio pricing, Copilot Credits, or agent usage estimation. Covers compute, storage, networking, databases, AI, Copilot Studio, and all other Azure se', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-azure", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "github/awesome-copilot"}', 'restricted', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-1827', 'copilot-azure-resource-health-diagnose', 'Azure Resource Health Diagnose', '1.0.0', 'infrastructure', 'Analyze Azure resource health, diagnose issues from logs and telemetry, and create a remediation plan for identified problems.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-azure", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "github/awesome-copilot"}', 'restricted', 10.0, 'draft', 'GitHub Copilot Community'),
