('ACU-SKILL-1907', 'copilot-git-commit', 'Git Commit', '1.0.0', 'cognitive', 'Execute git commit with conventional commit message analysis, intelligent staging, and message generation. Use when user asks to commit changes, create a git commit, or mentions "/commit". Supports: (1) Auto-detecting type and scope from changes, (2) Generating conventional commit messages from diff, (3) Interactive commit with optional type/scope/description overrides, (4) Intelligent file staging for logical grouping', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
