('ACU-SKILL-1910', 'copilot-github-issues', 'Github Issues', '1.0.0', 'infrastructure', 'Create, update, and manage GitHub issues using MCP tools. Use this skill when users want to create bug reports, feature requests, or task issues, update existing issues, add labels/assignees/milestones, set issue fields (dates, priority, custom fields), set issue types, or manage issue workflows. Triggers on requests like "create an issue", "file a bug", "request a feature", "update issue X", "set the priority", "set the start date", or any GitHub issue management task.', '{"thread": "T01 \u2014 COSM", "thread_code": "T01", "category": "mcp", "shard_affinity": "ADOCP", "layer_access": ["L5", "L6"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
