('ACU-SKILL-1912', 'copilot-image-manipulation-image-magick', 'Image Manipulation Image Magick', '1.0.0', 'cognitive', 'Process and manipulate images using ImageMagick. Supports resizing, format conversion, batch processing, and retrieving image metadata. Use when working with images, creating thumbnails, resizing wallpapers, or performing batch image operations.', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
