INSERT INTO marketplace_skills (skill_id, name, display_name, version, domain, description, manifest, governance_level, psi_minimum, status, author) VALUES
('ACU-SKILL-2010', 'copilot-update-specification', 'Update Specification', '1.0.0', 'cognitive', 'Update an existing specification file for the solution, optimized for Generative AI consumption based on new requirements or updates to any existing code.', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2011', 'copilot-vscode-ext-commands', 'Vscode Ext Commands', '1.0.0', 'cognitive', 'Guidelines for contributing commands in VS Code extensions. Indicates naming convention, visibility, localization and other relevant attributes, following VS Code extension development guidelines, libraries and good practices', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2012', 'copilot-vscode-ext-localization', 'Vscode Ext Localization', '1.0.0', 'cognitive', 'Guidelines for proper localization of VS Code extensions, following VS Code extension development guidelines, libraries and good practices', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2013', 'copilot-web-coder', 'Web Coder', '1.0.0', 'security', 'Expert 10x engineer with comprehensive knowledge of web development, internet protocols, and web standards. Use when working with HTML, CSS, JavaScript, web APIs, HTTP/HTTPS, web security, performance optimization, accessibility, or any web/internet concepts. Specializes in translating web terminology accurately and implementing modern web standards across frontend and backend development.', '{"thread": "T08 \u2014 ZURD", "thread_code": "T08", "category": "security", "shard_affinity": "Tenebris-ACIWS", "layer_access": ["L8", "L9", "L10"], "source_repo": "github/awesome-copilot"}', 'sovereign', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2014', 'copilot-web-design-reviewer', 'Web Design Reviewer', '1.0.0', 'cognitive', 'This skill enables visual inspection of websites running locally or remotely to identify and fix design issues. Triggers on requests like "review website design", "check the UI", "fix the layout", "find design problems". Detects issues with responsive design, accessibility, visual consistency, and layout breakage, then performs fixes at the source code level.', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2015', 'copilot-webapp-testing', 'Webapp Testing', '1.0.0', 'cognitive', 'Toolkit for interacting with and testing local web applications using Playwright. Supports verifying frontend functionality, debugging UI behavior, capturing browser screenshots, and viewing browser logs.', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2016', 'copilot-what-context-needed', 'What Context Needed', '1.0.0', 'cognitive', 'Ask Copilot what files it needs to see before answering a question', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2017', 'copilot-winapp-cli', 'Winapp Cli', '1.0.0', 'security', 'Windows App Development CLI (winapp) for building, packaging, and deploying Windows applications. Use when asked to initialize Windows app projects, create MSIX packages, generate AppxManifest.xml, manage development certificates, add package identity for debugging, sign packages, publish to the Microsoft Store, create external catalogs, or access Windows SDK build tools. Supports .NET (csproj), C++, Electron, Rust, Tauri, and cross-platform frameworks targeting Windows.', '{"thread": "T09 \u2014 Q-Suite", "thread_code": "T09", "category": "auth", "shard_affinity": "Q-ENC", "layer_access": ["L8", "L9", "L10"], "source_repo": "github/awesome-copilot"}', 'sovereign', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2018', 'copilot-winmd-api-search', 'Winmd Api Search', '1.0.0', 'cognitive', 'Find and explore Windows desktop APIs. Use when building features that need platform capabilities — camera, file access, notifications, UI controls, AI/ML, sensors, networking, etc. Discovers the right API for a task and retrieves full type details (methods, properties, events, enumeration values).', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2019', 'copilot-winui3-migration-guide', 'Winui3 Migration Guide', '1.0.0', 'cognitive', 'UWP-to-WinUI 3 migration reference. Maps legacy UWP APIs to correct Windows App SDK equivalents with before/after code snippets. Covers namespace changes, threading (CoreDispatcher to DispatcherQueue), windowing (CoreWindow to AppWindow), dialogs, pickers, sharing, printing, background tasks, and the most common Copilot code generation mistakes.', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "code-review", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2020', 'copilot-workiq-copilot', 'Workiq Copilot', '1.0.0', 'infrastructure', 'Guides the Copilot CLI on how to use the WorkIQ CLI/MCP server to query Microsoft 365 Copilot data (emails, meetings, docs, Teams, people) for live context, summaries, and recommendations.', '{"thread": "T01 \u2014 COSM", "thread_code": "T01", "category": "mcp", "shard_affinity": "ADOCP", "layer_access": ["L5", "L6"], "source_repo": "github/awesome-copilot"}', 'mandatory', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2021', 'copilot-write-coding-standards-from-file', 'Write Coding Standards From File', '1.0.0', 'infrastructure', 'Write a coding standards document for a project using the coding styles from the file(s) and/or folder(s) passed as arguments in the prompt.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "github/awesome-copilot"}', 'restricted', 10.0, 'draft', 'GitHub Copilot Community'),
('ACU-SKILL-2022', 'claude-api', 'Claude Api', '1.0.0', 'cognitive', 'Build apps with the Claude API or Anthropic SDK. TRIGGER when: code imports `anthropic`/`@anthropic-ai/sdk`/`claude_agent_sdk`, or user asks to use Claude API, Anthropic SDKs, or Agent SDK. DO NOT TRIGGER when: code imports `openai`/other AI SDK, general programming, or ML/data-science tasks.', '{"thread": "T01 \u2014 COSM", "thread_code": "T01", "category": "agent-patterns", "shard_affinity": "Diaran-MOE", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "anthropics/skills"}', 'mandatory', 10.0, 'draft', 'anthropics/skills'),
('ACU-SKILL-2023', 'docx', 'Docx', '1.0.0', 'cognitive', 'Use this skill whenever the user wants to create, read, edit, or manipulate Word documents (.docx files). Triggers include: any mention of ''Word doc'', ''word document'', ''.docx'', or requests to produce professional documents with formatting like tables of contents, headings, page numbers, or letterheads. Also use when extracting or reorganizing content from .docx files, inserting or replacing images in documents, performing find-and-replace in Word files, working with tracked changes or comm', '{"thread": "T03 \u2014 HISN", "thread_code": "T03", "category": "multimodal", "shard_affinity": "Baranurion-L1", "layer_access": ["L1", "L2", "L3"], "source_repo": "anthropics/skills"}', 'restricted', 10.0, 'draft', 'anthropics/skills'),
('ACU-SKILL-2024', 'internal-comms', 'Internal Comms', '1.0.0', 'cognitive', 'A set of resources to help me write all kinds of internal communications, using the formats that my company likes to use. Claude should use this skill whenever asked to write some sort of internal communications (status reports, leadership updates, 3P updates, company newsletters, FAQs, incident reports, project updates, etc.).', '{"thread": "T01 \u2014 COSM", "thread_code": "T01", "category": "general", "shard_affinity": "Diaran-MOE", "layer_access": ["L3", "L4", "L5"], "source_repo": "anthropics/skills"}', 'advisory', 10.0, 'draft', 'anthropics/skills'),
('ACU-SKILL-2025', 'pdf', 'Pdf', '1.0.0', 'cognitive', 'Use this skill whenever the user wants to do anything with PDF files. This includes reading or extracting text/tables from PDFs, combining or merging multiple PDFs into one, splitting PDFs apart, rotating pages, adding watermarks, creating new PDFs, filling PDF forms, encrypting/decrypting PDFs, extracting images, and OCR on scanned PDFs to make them searchable. If the user mentions a .pdf file or asks to produce one, use this skill.', '{"thread": "T03 \u2014 HISN", "thread_code": "T03", "category": "multimodal", "shard_affinity": "Baranurion-L1", "layer_access": ["L1", "L2", "L3"], "source_repo": "anthropics/skills"}', 'restricted', 10.0, 'draft', 'anthropics/skills'),
('ACU-SKILL-2026', 'pptx', 'Pptx', '1.0.0', 'commercial', 'Use this skill any time a .pptx file is involved in any way — as input, output, or both. This includes: creating slide decks, pitch decks, or presentations; reading, parsing, or extracting text from any .pptx file (even if the extracted content will be used elsewhere, like in an email or summary); editing, modifying, or updating existing presentations; combining or splitting slide files; working with templates, layouts, speaker notes, or comments. Trigger whenever the user mentions "deck," "slid', '{"thread": "T14 \u2014 NAHRA", "thread_code": "T14", "category": "design", "shard_affinity": "Commercial", "layer_access": ["L3", "L4", "L5"], "source_repo": "anthropics/skills"}', 'advisory', 10.0, 'draft', 'anthropics/skills'),
('ACU-SKILL-2027', 'xlsx', 'Xlsx', '1.0.0', 'cognitive', 'Use this skill any time a spreadsheet file is the primary input or output. This means any task where the user wants to: open, read, edit, or fix an existing .xlsx, .xlsm, .csv, or .tsv file (e.g., adding columns, computing formulas, formatting, charting, cleaning messy data); create a new spreadsheet from scratch or from other data sources; or convert between tabular file formats. Trigger especially when the user references a spreadsheet file by name or path — even casually (like "the xlsx in my', '{"thread": "T04 \u2014 ACIW", "thread_code": "T04", "category": "coding", "shard_affinity": "AcuTect-CODEX", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "anthropics/skills"}', 'mandatory', 10.0, 'draft', 'anthropics/skills'),
('ACU-SKILL-2028', 'vercel-composition-patterns', 'Vercel Composition Patterns', '1.0.0', 'commercial', 'React composition patterns that scale. Use when refactoring components with boolean prop proliferation, building flexible component libraries, or designing reusable APIs. Triggers on tasks involving compound components, render props, context providers, or component architecture. Includes React 19 API changes.', '{"thread": "T14 \u2014 NAHRA", "thread_code": "T14", "category": "design", "shard_affinity": "Commercial", "layer_access": ["L3", "L4", "L5"], "source_repo": "vercel-labs/agent-skills"}', 'advisory', 10.0, 'draft', 'vercel-labs/agent-skills'),
('ACU-SKILL-2029', 'deploy-to-vercel', 'Deploy To Vercel', '1.0.0', 'infrastructure', 'Deploy applications and websites to Vercel. Use when the user requests deployment actions like "deploy my app", "deploy and give me the link", "push this live", or "create a preview deployment".', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "devops", "shard_affinity": "Watad", "layer_access": ["L5", "L6", "L7"], "source_repo": "vercel-labs/agent-skills"}', 'restricted', 10.0, 'draft', 'vercel-labs/agent-skills'),
('ACU-SKILL-2030', 'vercel-react-best-practices', 'Vercel React Best Practices', '1.0.0', 'cognitive', 'React and Next.js performance optimization guidelines from Vercel Engineering. This skill should be used when writing, reviewing, or refactoring React/Next.js code to ensure optimal performance patterns. Triggers on tasks involving React components, Next.js pages, data fetching, bundle optimization, or performance improvements.', '{"thread": "T02 \u2014 DIAR", "thread_code": "T02", "category": "search", "shard_affinity": "APMS", "layer_access": ["L4", "L5", "L6"], "source_repo": "vercel-labs/agent-skills"}', 'restricted', 10.0, 'draft', 'vercel-labs/agent-skills'),
('ACU-SKILL-2031', 'vercel-react-native-skills', 'Vercel React Native Skills', '1.0.0', 'commercial', 'React Native and Expo best practices for building performant mobile apps. Use when building React Native components, optimizing list performance, implementing animations, or working with native modules. Triggers on tasks involving React Native, Expo, mobile performance, or native platform APIs.', '{"thread": "T14 \u2014 NAHRA", "thread_code": "T14", "category": "design", "shard_affinity": "Commercial", "layer_access": ["L3", "L4", "L5"], "source_repo": "vercel-labs/agent-skills"}', 'advisory', 10.0, 'draft', 'vercel-labs/agent-skills'),
('ACU-SKILL-2032', 'api-gateway', 'Api Gateway', '1.0.0', 'infrastructure', 'AWS API Gateway for REST and HTTP API management. Use when creating APIs, configuring integrations, setting up authorization, managing stages, implementing rate limiting, or troubleshooting API issues.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
('ACU-SKILL-2033', 'bedrock', 'Bedrock', '1.0.0', 'infrastructure', 'AWS Bedrock foundation models for generative AI. Use when invoking foundation models, building AI applications, creating embeddings, configuring model access, or implementing RAG patterns.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
('ACU-SKILL-2034', 'cloudformation', 'Cloudformation', '1.0.0', 'infrastructure', 'AWS CloudFormation infrastructure as code for stack management. Use when writing templates, deploying stacks, managing drift, troubleshooting deployments, or organizing infrastructure with nested stacks.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
('ACU-SKILL-2035', 'cloudwatch', 'Cloudwatch', '1.0.0', 'infrastructure', 'AWS CloudWatch monitoring for logs, metrics, alarms, and dashboards. Use when setting up monitoring, creating alarms, querying logs with Insights, configuring metric filters, building dashboards, or troubleshooting application issues.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
