('ACU-SKILL-2037', 'dynamodb', 'Dynamodb', '1.0.0', 'infrastructure', 'AWS DynamoDB NoSQL database for scalable data storage. Use when designing table schemas, writing queries, configuring indexes, managing capacity, implementing single-table design, or troubleshooting performance issues.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
