('ACU-SKILL-2039', 'ecs', 'Ecs', '1.0.0', 'infrastructure', 'AWS ECS container orchestration for running Docker containers. Use when deploying containerized applications, configuring task definitions, setting up services, managing clusters, or troubleshooting container issues.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
