('ACU-SKILL-2041', 'eventbridge', 'Eventbridge', '1.0.0', 'infrastructure', 'AWS EventBridge serverless event bus for event-driven architectures. Use when creating rules, configuring event patterns, setting up scheduled events, integrating with SaaS, or building cross-account event routing.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
('ACU-SKILL-2042', 'iam', 'Iam', '1.0.0', 'security', 'AWS Identity and Access Management for users, roles, policies, and permissions. Use when creating IAM policies, configuring cross-account access, setting up service roles, troubleshooting permission errors, or managing access control.', '{"thread": "T09 \u2014 Q-Suite", "thread_code": "T09", "category": "auth", "shard_affinity": "Q-ENC", "layer_access": ["L8", "L9", "L10"], "source_repo": "itsmostafa/aws-agent-skills"}', 'sovereign', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
