('ACU-SKILL-2045', 's3', 'S3', '1.0.0', 'infrastructure', 'AWS S3 object storage for bucket management, object operations, and access control. Use when creating buckets, uploading files, configuring lifecycle policies, setting up static websites, managing permissions, or implementing cross-region replication.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "itsmostafa/aws-agent-skills"}', 'restricted', 10.0, 'draft', 'itsmostafa/aws-agent-skills'),
