('ACU-SKILL-2050', 'find-skills', 'Find Skills', '1.0.0', 'cognitive', 'Helps users discover and install agent skills when they ask questions like "how do I do X", "find a skill for X", "is there a skill that can...", or express interest in extending capabilities. This skill should be used when the user is looking for functionality that might exist as an installable skill.', '{"thread": "T01 \u2014 COSM", "thread_code": "T01", "category": "agent-patterns", "shard_affinity": "Diaran-MOE", "layer_access": ["L5", "L6", "L7", "L8"], "source_repo": "vercel-labs/skills"}', 'mandatory', 10.0, 'draft', 'vercel-labs/skills'),
('ACU-SKILL-2051', 'agents-sdk', 'Agents Sdk', '1.0.0', 'infrastructure', 'Build AI agents on Cloudflare Workers using the Agents SDK. Load when creating stateful agents, durable workflows, real-time WebSocket apps, scheduled tasks, MCP servers, or chat applications. Covers Agent class, state management, callable RPC, Workflows integration, and React hooks. Biases towards retrieval from Cloudflare docs over pre-trained knowledge.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-aws", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "cloudflare/skills"}', 'restricted', 10.0, 'draft', 'cloudflare/skills'),
