('ACU-SKILL-2168', 'wiki-ado-convert', 'Wiki Ado Convert', '1.0.0', 'infrastructure', 'Converts VitePress/GFM wiki markdown to Azure DevOps Wiki-compatible format. Generates a Node.js build script that transforms Mermaid syntax, strips front matter, fixes links, and outputs ADO-compatible copies to dist/ado-wiki/.', '{"thread": "T13 \u2014 ACAI V2", "thread_code": "T13", "category": "cloud-azure", "shard_affinity": "Marel", "layer_access": ["L5", "L6", "L7"], "source_repo": "microsoft/skills"}', 'restricted', 10.0, 'draft', 'Microsoft'),
